"""Export harness honesty Table 8 (Pass/Partial/Fail) from B5 baseline CSV."""

from __future__ import annotations

from pathlib import Path

from dualexis.evaluation.harness_b5_alignment import (
    HarnessB5Alignment,
    load_harness_b5_alignment,
)

AUTO_GENERATED_BANNER = (
    "% Auto-generated by dualexis evaluation harness_b5_labels_export.\n"
    "% Do not edit manually; regenerate via: experiment export-harness-b5-labels\n"
)


def render_harness_b5_labels_latex(alignment: HarnessB5Alignment) -> str:
    """Build LaTeX for tab:harness-b5-by-scenario."""
    seed_count = alignment.seed_count
    lines = [
        AUTO_GENERATED_BANNER.rstrip("\n"),
        "",
        "\\begin{table}[htbp]",
        "  \\centering",
        "  \\caption{Reference orchestration path \\textbf{harness honesty labels} vs.\\ "
        "procedural ground truth by scenario "
        f"($N={seed_count}$ seeds). Pass/Partial/Fail derive from mean B5 "
        "\\texttt{event\\_detection\\_accuracy}: Pass $=1.0$, Fail $=0.0$, "
        "Partial otherwise. Labels document placeholder-pipeline divergence for benchmark "
        "transparency, not TSGG schema conformance or detection capability. "
        "Multiseed B1--B5 harness diagnostics: online supplementary material "
        "(Appendix~\\ref{app:online-material}).}",
        "  \\label{tab:harness-b5-by-scenario}",
        "  \\small",
        "  \\begin{tabular}{@{}ll@{}}",
        "    \\toprule",
        "    Scenario & Outcome \\\\",
        "    \\midrule",
    ]
    for row in alignment.rows:
        scenario_tex = row.scenario.replace("_", r"\_")
        lines.append(f"    {scenario_tex} & {row.label} \\\\")
    lines.extend(
        [
            "    \\bottomrule",
            "  \\end{tabular}",
            "\\end{table}",
            "",
        ]
    )
    return "\n".join(lines)


def export_harness_b5_labels_tex(
    output_path: Path = Path("results_reference/tables/harness_b5_by_scenario.tex"),
    *,
    alignment: HarnessB5Alignment | None = None,
    baseline_csv: Path | None = None,
    paper_baseline: str = "B5",
) -> Path:
    """Write Table 8 LaTeX from alignment or loaded baseline CSV."""
    resolved = alignment or load_harness_b5_alignment(
        baseline_csv or Path("results/baseline_comparison/results.csv"),
        paper_baseline=paper_baseline,
    )
    target = output_path.resolve()
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(render_harness_b5_labels_latex(resolved), encoding="utf-8")
    return target


__all__ = [
    "AUTO_GENERATED_BANNER",
    "export_harness_b5_labels_tex",
    "render_harness_b5_labels_latex",
]
